  ('optician-moex-01442', 'optician', 'optician-moex-109-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '硬式透氣鏡片的後表面光學區直徑（BOZD）為8.0mm及後表面光學區曲率半徑（BOZR）為7.80mm， 現將BOZD加大為9.0mm，若要維持相同鏡片配適鬆緊度，則BOZR需相應調整為：', '["變小為7.75mm", "不變，維持7.80mm", "變大為7.85mm", "變大為7.90mm"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:33+00:00", "source_pdf_sha1": "ae4233b96821", "answer_pdf_sha1": "fc9bd5d8075c", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01443', 'optician', 'optician-moex-109-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關硬式透氣隱形眼鏡螢光染色評估方法的敘述，何者錯誤？', '["生物顯微鏡（biomicroscope）可調整放大倍率、亮度及光條寬度", "BurtonLamp（「布頓」伍氏螢光燈）容易使用但只能觀察單眼狀況", "BurtonLamp（「布頓」伍氏螢光燈）為使用UV螢光燈及+5.00D之放大鏡進行觀察", "黃色濾光片搭配適當光源可進行鏡片後面之螢光染色狀況"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:33+00:00", "source_pdf_sha1": "ae4233b96821", "answer_pdf_sha1": "fc9bd5d8075c", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01444', 'optician', 'optician-moex-109-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '小華驗配了硬式隱形眼鏡後來診所回診，在螢光染劑靜態評估中發現3和9點鐘方向的染色情形（3and9 o''clockstaining），則原因最不可能為何？', '["鏡片定位不佳", "護理毒性反應", "眨眼不完全", "鏡片邊緣厚度過厚"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:33+00:00", "source_pdf_sha1": "ae4233b96821", "answer_pdf_sha1": "fc9bd5d8075c", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01445', 'optician', 'optician-moex-109-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關角膜弧度測量儀的敘述，下列何者錯誤？', '["可以測得角膜表面的曲率變化及其屈光度", "測出的屈光度數大部分來自角膜前表面", "有時候會受到眼球調適作用而影響到所量測的屈光度", "所測量的曲率半徑是隱形眼鏡處方的重要依據"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:33+00:00", "source_pdf_sha1": "ae4233b96821", "answer_pdf_sha1": "fc9bd5d8075c", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01446', 'optician', 'optician-moex-109-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '角膜弧度儀檢查顯示 42.00D@180/42.25D@90，自動驗光儀檢查為-2.00DS/-1.00DC×090，則扣除角膜前 表面的散光之後，眼球內部呈現的散光為？', '["-0.75DC×090", "-0.75DC×180", "-1.25DC×090", "-1.25DC×180"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:33+00:00", "source_pdf_sha1": "ae4233b96821", "answer_pdf_sha1": "fc9bd5d8075c", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01447', 'optician', 'optician-moex-109-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關細隙燈的檢查，下列敘述何者錯誤？', '["觀察下眼瞼緣淚鏡（tearmeniscus）的高度可判斷有無乾眼症", "觀察淚液破裂時間（TBUT），可判斷淚液的品質", "以螢光染色觀察角膜破皮，加上黃色Wratten12濾片，可看得更清楚", "以玫瑰紅（rosebengal）染劑，將結膜染色，以白光觀察是否有乾眼症"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:33+00:00", "source_pdf_sha1": "ae4233b96821", "answer_pdf_sha1": "fc9bd5d8075c", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01448', 'optician', 'optician-moex-109-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關細隙燈照明系統的濾片（filter），可強化組織的觀察，下列敘述何者錯誤？', '["用綠色濾片來觀察角膜上的血管，可增加對比度", "用綠色濾片來觀察玫瑰紅在角結膜的染色，可增加染色部位的能見度", "角膜活體螢光染色，以鈷藍光（cobaltbluefilter）來觀察，淚液呈現綠色", "用麗絲安綠（lissaminegreen），將角結膜染色，以黃色Wratten12濾片觀察可增加對比色度"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:33+00:00", "source_pdf_sha1": "ae4233b96821", "answer_pdf_sha1": "fc9bd5d8075c", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL)
